<template><header class='top'>纽约 {{ny}} • 瓦伦西亚 {{va}} • 上海 {{sh}}<span class='user'>guest<button @click=''>退出</button></span></header></template>
<script setup>import {ref,onMounted} from 'vue';const ny=ref(''),va=ref(''),sh=ref('');function tick(){const d=new Date();ny.value=d.toLocaleTimeString('zh-CN',{timeZone:'America/New_York',hour12:false});va.value=d.toLocaleTimeString('zh-CN',{timeZone:'Europe/Madrid',hour12:false});sh.value=d.toLocaleTimeString('zh-CN',{timeZone:'Asia/Shanghai',hour12:false});}onMounted(()=>{tick();setInterval(tick,1000)})</script>
<style scoped>.top{height:60px;background:#00202A;color:#0f0;display:flex;align-items:center;padding:0 16px}.user{margin-left:auto}</style>